Part.Source:
&sdtItensTabelaImposto.EmpCod = &EmpCod
//abriu o arquivo &ExcelDocument.Open(&CaminhoArquivoXml)
//Pega Grupo imposto Filial &Mensagem = &ExcelDocument.Cells(1, 3).Value &Mensagem = &Mensagem.Replace('FILIAL: ', '') &Mensagem = &Mensagem.Trim() For Each Order EmpCod, TbImpFilCod Where EmpCod = &EmpCod Where TbImpFilCodNom = &Mensagem &sdtItensTabelaImposto.ImpFilCod = TbImpFilCod &sdtItensTabelaImposto.ImpFilNom = TbImpFilNom Exit When none &sdtItensTabelaImposto.ImpFilNom = 'NÃO ENCONTRADO: ' + &Mensagem.Trim() EndFor
////LANCAMENTO &Mensagem = &ExcelDocument.Cells(1, 9).Value &Mensagem = &Mensagem.Replace('LCTO: ', '') &Mensagem = &Mensagem.Trim() For Each Order EmpCod, LctCod Where EmpCod = &EmpCod Where LctCodNom = &Mensagem &sdtItensTabelaImposto.ImpLctCod = LctCod &sdtItensTabelaImposto.ImpLctNom = LctNom Exit When none &sdtItensTabelaImposto.ImpLctNom = 'NÃO ENCONTRADO: ' + &Mensagem.Trim() EndFor
////UF &Mensagem = &ExcelDocument.Cells(1, 20).Value &Mensagem = &Mensagem.Replace('UF: ', '') &Mensagem = &Mensagem.Trim() For Each Order EmpCod, UfeCod where EmpCod = &EmpCod Where UfeCod = &Mensagem &sdtItensTabelaImposto.ImpUfeCod = UfeCod &sdtItensTabelaImposto.ImpUfeNom = UfeNom Exit When none &sdtItensTabelaImposto.ImpUfeNom = 'NÃO ENCONTRADO: ' + &Mensagem.Trim() EndFor
////PESSOA &Mensagem = &ExcelDocument.Cells(1, 26).Value &Mensagem = &Mensagem.Replace('PESSOA: ', '') &Mensagem = &Mensagem.Trim() For Each Order EmpCod, GruImpCod Where EmpCod = &EmpCod Where GruImpCodNom = &Mensagem &sdtItensTabelaImposto.ImpGruImpCod = GruImpCod &sdtItensTabelaImposto.ImpGruImpNom = GruImpNom Exit When none &sdtItensTabelaImposto.ImpGruImpNom = 'NÃO ENCONTRADO: ' + &Mensagem.Trim() EndFor
//Navega entre as Categorias dos Produtos &linha = 6 &Iscontinua = true &IsAchouVersao = false
do while &Iscontinua = true //VERSAO: 2.0.0
&ImpCatCodNom = &ExcelDocument.Cells(&linha, 1).Value &ImpCatCodNom = trim(&ImpCatCodNom) if Substr(&ImpCatCodNom, 1, 6) = 'VERSAO' or &QtdVazio = 100 if Substr(&ImpCatCodNom, 1, 6) = 'VERSAO' &IsAchouVersao = true Endif &Iscontinua = false Else
&ErroLancamentoVarchar = '' &ErroLancamentoMensagem = '' if not &ImpCatCodNom.IsEmpty() &QtdVazio = 0 &sdtItensTabelaImpostoItem = new()
//Preenche campos do xlsx //Produto &sdtItensTabelaImpostoItem.ImpCatCodNom = &ImpCatCodNom
For Each order EmpCod, CatCodImp Where EmpCod = &EmpCod Where CatCodImp = &sdtItensTabelaImpostoItem.ImpCatCodNom //&ImpCatCodNom = CatCodImp //CatCodNom
&sdtItensTabelaImpostoItem.ImpCatCod = CatCod &sdtItensTabelaImpostoItem.ImpCatNom = CatNom Exit When none &ErroLancamentoVarchar = 'E' &ErroLancamentoMensagem = 'CATEGORIA IMPOSTO PRODUTO NÃO CADASTRADA' &sdtItensTabelaImpostoItem.ImpCatNom = 'NÃO ENCONTRADO' EndFor
&sdtItensTabelaImpostoItem.ErroLancamento = &ErroLancamentoVarchar &sdtItensTabelaImpostoItem.ErroLancamentoMensagem = &ErroLancamentoMensagem
&Coluna = 3 //Cfop &sdtItensTabelaImpostoItem.ImpCfoCod = FormataCFOP.Udp(&ExcelDocument.Cells(&linha, &Coluna).Value) &Coluna += 1 //CSOSN / CST &sdtItensTabelaImpostoItem.SitCod.FromString(&ExcelDocument.Cells(&linha, &Coluna).Text)
&Coluna += 2 //vazio
//ALIQ. ICMS &sdtItensTabelaImpostoItem.ImpAlqIcmInt = val(&ExcelDocument.Cells(&linha, &Coluna).Text , ',') &Coluna += 1 //REDUCAO ICMS &sdtItensTabelaImpostoItem.ImpRedAlqIcmInt = val(&ExcelDocument.Cells(&linha, &Coluna).Value, ',') &Coluna += 1 //DIFERIMENTO ICMS &sdtItensTabelaImpostoItem.ImpDif = val(&ExcelDocument.Cells(&linha, &Coluna).Value, ',') &Coluna += 1 //DIFAL ICMS &sdtItensTabelaImpostoItem.ImpALqIcmUFDest = val(&ExcelDocument.Cells(&linha, &Coluna).Value, ',') &Coluna += 1 //COD. CBENEF &sdtItensTabelaImpostoItem.ImpCBenef = &ExcelDocument.Cells(&linha, &Coluna).Value &Coluna += 1 //COD DESEONERACAO &sdtItensTabelaImpostoItem.ImpIcmsMotDes.FromString(&ExcelDocument.Cells(&linha, &Coluna).Value) if &sdtItensTabelaImpostoItem.ImpIcmsMotDes = '0' &sdtItensTabelaImpostoItem.ImpIcmsMotDes = '' Endif &Coluna += 1
//DESTACAR ICMS RETIDO Do Case case upper(&ExcelDocument.Cells(&linha, &Coluna).Value) = 'SIM' &sdtItensTabelaImpostoItem.ImpIcmsRet = 'S' case upper(&ExcelDocument.Cells(&linha, &Coluna).Value) = 'NAO' &sdtItensTabelaImpostoItem.ImpIcmsRet = 'N' EndCAse &Coluna += 1
//EXCLUIR ICMS DA BASE Do Case case upper(&ExcelDocument.Cells(&linha, &Coluna).Value) = 'SIM' &sdtItensTabelaImpostoItem.ImpExcPisCofins = 'S' case upper(&ExcelDocument.Cells(&linha, &Coluna).Value) = 'NAO' &sdtItensTabelaImpostoItem.ImpExcPisCofins = '' EndCAse
&Coluna += 2 //VAZIO
//ALIQ ICMS ST &sdtItensTabelaImpostoItem.ImpAlqIcmExt = val(&ExcelDocument.Cells(&linha, &Coluna).Text, ',') &Coluna += 1 //MVA ICMS ST &sdtItensTabelaImpostoItem.ImpAlqMVA = val(&ExcelDocument.Cells(&linha, &Coluna).Value, ',') &Coluna += 1 //REDUCAO ICMS ST &sdtItensTabelaImpostoItem.ImpRedAlqIcmExt = val(&ExcelDocument.Cells(&linha, &Coluna).Value , ',') &Coluna += 1 //FECOP ICMS ST &sdtItensTabelaImpostoItem.ImpTaxFecop = val(&ExcelDocument.Cells(&linha, &Coluna).Value, ',') &Coluna += 1 //DIFAL S.T &sdtItensTabelaImpostoItem.ImpAlqIcmStUF = val(&ExcelDocument.Cells(&linha, &Coluna).Value, ',')
&Coluna += 2 //VAZIO
//ALIQ IPI &sdtItensTabelaImpostoItem.ImpIPI = val(&ExcelDocument.Cells(&linha, &Coluna).Value, ',') &Coluna += 1
//CST IPI &Varchar = &ExcelDocument.Cells(&linha, &Coluna).Value &Varchar = &Varchar.Trim() if not &Varchar.IsEmpty() &Varchar = padL(&Varchar, 2, '0') EndIf &sdtItensTabelaImpostoItem.ImpCstIpi.FromString(&Varchar) &Coluna += 1
//INCLUIR NA BASE DO ICMS Do Case case upper(&ExcelDocument.Cells(&linha, &Coluna).Value) = 'ICMS ST' &sdtItensTabelaImpostoItem.ImpIncIpi = 'S' case upper(&ExcelDocument.Cells(&linha, &Coluna).Value) = 'ICMS' &sdtItensTabelaImpostoItem.ImpIncIpi = 'I' Otherwise &sdtItensTabelaImpostoItem.ImpIncIpi = '' EndCAse &Coluna += 1
//COD ENQUADRAMENTO &sdtItensTabelaImpostoItem.ImpIpiEnq = val(&ExcelDocument.Cells(&linha, &Coluna).Value)
&Coluna += 2 //VAZIO
//ALIQ PIS &sdtItensTabelaImpostoItem.ImpPis = val(&ExcelDocument.Cells(&linha, &Coluna).Value, ',') &Coluna += 1 //REDUCAO PIS &sdtItensTabelaImpostoItem.ImpPisRed = val( &ExcelDocument.Cells(&linha, &Coluna).Value, ',') &Coluna += 1
//CST PIS &Varchar = &ExcelDocument.Cells(&linha, &Coluna).Value &Varchar = &Varchar.Trim() if not &Varchar.IsEmpty() &Varchar = padL(&Varchar, 2, '0') EndIf &sdtItensTabelaImpostoItem.ImpCstPis.FromString(&Varchar)
&Coluna += 2 //VAZIO
//ALIQ COFINS &sdtItensTabelaImpostoItem.ImpCofins = Val(&ExcelDocument.Cells(&linha, &Coluna).Value, ',') &Coluna += 1 //REDUCAO COFINS &sdtItensTabelaImpostoItem.ImpCofinsRed = val(&ExcelDocument.Cells(&linha, &Coluna).Value, ',') &Coluna += 1
//CST COFINS &Varchar = &ExcelDocument.Cells(&linha, &Coluna).Value &Varchar = &Varchar.Trim() if not &Varchar.IsEmpty() &Varchar = padL(&Varchar, 2, '0') EndIf &sdtItensTabelaImpostoItem.ImpCstCofins.FromString(&Varchar)
&sdtObservacaoNota.Clear()
//VALIDACOES &ErroCfopMensagem = validaCfopTabelaImposto.UDP(&EmpCod, &sdtItensTabelaImposto.ImpFilCod, &sdtItensTabelaImposto.ImpLctCod, &sdtItensTabelaImposto.ImpUfeCod, &sdtItensTabelaImpostoItem.ImpCfoCod) &ErroCstMensagem = validaSituacaoTributaria.Udp(&EmpCod, &sdtItensTabelaImposto.ImpFilCod, &sdtItensTabelaImpostoItem.SitCod) &Numeric = val(&sdtItensTabelaImpostoItem.ImpCstIpi) &Varchar = Substr(&sdtItensTabelaImpostoItem.ImpCfoCod, 1, 1)
if not &ErroCfopMensagem.IsEmpty() &sdtItensTabelaImpostoItem.ErroLancamento = 'E'
&sdtObservacaoNotaItem = new() &sdtObservacaoNotaItem.ObsCod = 0 &sdtObservacaoNotaItem.ObsNom = &ErroCfopMensagem &sdtObservacaoNotaItem.ObsSts = 'Z' &sdtObservacaoNota.Add(&sdtObservacaoNotaItem) ENdif if not &ErroCstMensagem.IsEmpty() &sdtItensTabelaImpostoItem.ErroLancamento = 'E'
&sdtObservacaoNotaItem = new() &sdtObservacaoNotaItem.ObsCod = 0 &sdtObservacaoNotaItem.ObsNom = &ErroCstMensagem &sdtObservacaoNotaItem.ObsSts = 'Z' &sdtObservacaoNota.Add(&sdtObservacaoNotaItem) EndIf
If (&sdtItensTabelaImpostoItem.ImpAlqIcmInt > &sdtItensTabelaImpostoItem.ImpAlqIcmExt and (&sdtItensTabelaImpostoItem.ImpAlqMVA = 0 and &sdtItensTabelaImpostoItem.ImpRedAlqIcmInt = 0)) and &sdtItensTabelaImpostoItem.ImpAlqIcmExt > 0 &sdtItensTabelaImpostoItem.ErroLancamento = 'E'
&sdtObservacaoNotaItem = new() &sdtObservacaoNotaItem.ObsCod = 0 &sdtObservacaoNotaItem.ObsNom = 'Alíq.Interna (ICMS) não pode ser maior que a Alíq.Externa (ICMS S.T)' &sdtObservacaoNotaItem.ObsSts = 'Z' &sdtObservacaoNota.Add(&sdtObservacaoNotaItem) EndIf
Do Case Case &Varchar in ('5','6','7') and &Numeric < 50 &sdtItensTabelaImpostoItem.ErroLancamento = 'E'
&sdtObservacaoNotaItem = new() &sdtObservacaoNotaItem.ObsCod = 0 &sdtObservacaoNotaItem.ObsNom = 'PARA CFOPs INICIADOS EM 5,6,7 CST IPI DEVE SER MAIOR/IGUAL QUE 50' &sdtObservacaoNotaItem.ObsSts = 'Z' &sdtObservacaoNota.Add(&sdtObservacaoNotaItem)
Case &Varchar in ('1','2','3') and &Numeric >= 50 &sdtItensTabelaImpostoItem.ErroLancamento = 'E'
&sdtObservacaoNotaItem = new() &sdtObservacaoNotaItem.ObsCod = 0 &sdtObservacaoNotaItem.ObsNom = 'PARA CFOPs INICIADOS EM 1,2,3 CST IPI DEVE SER MENOR QUE 50' &sdtObservacaoNotaItem.ObsSts = 'Z' &sdtObservacaoNota.Add(&sdtObservacaoNotaItem) Endcase
do 'validaCFOP' If &sdtItensTabelaImpostoItem.ImpCfoCod.IsEmpty() or &IsAchouCfop = false &sdtItensTabelaImpostoItem.ErroLancamento = 'E'
&sdtObservacaoNotaItem = new() &sdtObservacaoNotaItem.ObsCod = 0 &sdtObservacaoNotaItem.ObsNom = 'CFOP Inválido!' &sdtObservacaoNotaItem.ObsSts = 'Z' &sdtObservacaoNota.Add(&sdtObservacaoNotaItem) Endif If &sdtItensTabelaImpostoItem.ImpALqIcmUFDest > 0 and (&sdtItensTabelaImpostoItem.ImpALqIcmUFDest < &sdtItensTabelaImpostoItem.ImpAlqIcmInt or &sdtItensTabelaImpostoItem.ImpAlqIcmInt.IsEmpty()) &sdtItensTabelaImpostoItem.ErroLancamento = 'E'
&sdtObservacaoNotaItem = new() &sdtObservacaoNotaItem.ObsCod = 0 &sdtObservacaoNotaItem.ObsNom = 'Valor do (DIFAL)%.UF.Dest., deve ser aliquota do icms + o difal, não pode se menor que a aliquota do icms!' &sdtObservacaoNotaItem.ObsSts = 'Z' &sdtObservacaoNota.Add(&sdtObservacaoNotaItem) Endif
if &sdtItensTabelaImpostoItem.SitCod = 51 and (&sdtItensTabelaImpostoItem.ImpRedAlqIcmInt > 0 or &sdtItensTabelaImpostoItem.ImpAlqIcmExt > 0 ) //Dar erro ao informar dados de icms st quando sit = 51 &sdtItensTabelaImpostoItem.ErroLancamento = 'E'
&sdtObservacaoNotaItem = new() &sdtObservacaoNotaItem.ObsCod = 0 &sdtObservacaoNotaItem.ObsNom = 'CST 51, não deve possui redução do ICMS e nem % S.T' &sdtObservacaoNotaItem.ObsSts = 'Z' &sdtObservacaoNota.Add(&sdtObservacaoNotaItem) Endif
if &sdtItensTabelaImpostoItem.SitCod = 51 and (&sdtItensTabelaImpostoItem.ImpDif = 0 ) &sdtItensTabelaImpostoItem.ErroLancamento = 'E'
&sdtObservacaoNotaItem = new() &sdtObservacaoNotaItem.ObsCod = 0 &sdtObservacaoNotaItem.ObsNom = 'CST 51, Não informado o valor do Diferimento para CST Diferido.' &sdtObservacaoNotaItem.ObsSts = 'Z' &sdtObservacaoNota.Add(&sdtObservacaoNotaItem) Endif
if &sdtItensTabelaImpostoItem.ImpALqIcmUFDest > 0 and (&sdtItensTabelaImpostoItem.ImpALqIcmUFDest < &sdtItensTabelaImpostoItem.ImpAlqIcmInt or &sdtItensTabelaImpostoItem.ImpAlqIcmInt.IsEmpty()) &sdtItensTabelaImpostoItem.ErroLancamento = 'E'
&sdtObservacaoNotaItem = new() &sdtObservacaoNotaItem.ObsCod = 0 &sdtObservacaoNotaItem.ObsNom = 'Valor do (DIFAL)%.UF.Dest., deve ser aliquota do icms + o difal, não pode se menor que a aliquota do icms!' &sdtObservacaoNotaItem.ObsSts = 'Z' &sdtObservacaoNota.Add(&sdtObservacaoNotaItem) Endif
//VALIDA CODIGO IPI &IsErroIpi = false Do Case //Se o CST de IPI for de Imunidade (“04” de Entrada ou “54” de Saída), o Código de Enquadramento deve ser de "001” a “099”; Case &sdtItensTabelaImpostoItem.ImpCstIpi in ('04','54') If (&sdtItensTabelaImpostoItem.ImpIpiEnq = 0 or &sdtItensTabelaImpostoItem.ImpIpiEnq > 99) &MensagemErroIpi = 'Se o CST de IPI for de Imunidade (“04” de Entrada ou “54” de Saída), o Código de Enquadramento deve ser de "001” a “099”' &IsErroIpi = true Endif
//Se o CST de IPI for de Suspensão (“05” de Entrada ou “55” de Saída), o Código de Enquadramento deve ser de "101” a “199”; Case &sdtItensTabelaImpostoItem.ImpCstIpi in ('05','55') if (&sdtItensTabelaImpostoItem.ImpIpiEnq < 101 or &sdtItensTabelaImpostoItem.ImpIpiEnq > 199) &MensagemErroIpi = 'Se o CST de IPI for de Suspensão (“05” de Entrada ou “55” de Saída), o Código de Enquadramento deve ser de "101” a “199”;' &IsErroIpi = true Endif //Se o CST de IPI for de Isenção (“02” de Entrada ou “52” de Saída), o Código de Enquadramento deve ser de "301” a “399”; Case &sdtItensTabelaImpostoItem.ImpCstIpi in ('02','52') if (&sdtItensTabelaImpostoItem.ImpIpiEnq < 301 or &sdtItensTabelaImpostoItem.ImpIpiEnq > 399) &MensagemErroIpi = 'Se o CST de IPI for de Isenção (“02” de Entrada ou “52” de Saída), o Código de Enquadramento deve ser de "301” a “399”' &IsErroIpi = true Endif
//Se o CST de IPI for de Redução (“49” de Entrada ou “99” de Saída), o Código de Enquadramento deve ser de "601” a “608”; Case &sdtItensTabelaImpostoItem.ImpCstIpi in ('49','99') if (&sdtItensTabelaImpostoItem.ImpIpiEnq < 601 or &sdtItensTabelaImpostoItem.ImpIpiEnq > 608) and &sdtItensTabelaImpostoItem.ImpIPI > 0 //SO SE PREENCHEU A ALIQ. &MensagemErroIpi = 'Se o CST de IPI for de Redução (“49” de Entrada ou “99” de Saída), o Código de Enquadramento deve ser de "601” a “608”' &IsErroIpi = true Endif
otherwise //E para a tributação normal de IPI ou para “Outros”, o Código de Enquadramento deve ser de "999”.
if &sdtItensTabelaImpostoItem.ImpIpiEnq <> 999 and not &sdtItensTabelaImpostoItem.ImpIpiEnq.IsEmpty() &IsErroIpi = true &MensagemErroIpi = 'para a tributação normal de IPI ou para “Outros”, o Código de Enquadramento deve ser de "999”' EndIf EndCAse if &IsErroIpi = true &sdtItensTabelaImpostoItem.ErroLancamento = 'E'
&sdtObservacaoNotaItem = new() &sdtObservacaoNotaItem.ObsCod = 0 &sdtObservacaoNotaItem.ObsNom = &MensagemErroIpi &sdtObservacaoNotaItem.ObsSts = 'Z' &sdtObservacaoNota.Add(&sdtObservacaoNotaItem) Endif
//VALIDACOES
&sdtItensTabelaImpostoItem.ObservacaoLongVarchar = &sdtObservacaoNota.ToJson()
&sdtItensTabelaImposto.Itens.Add(&sdtItensTabelaImpostoItem) Else &QtdVazio += 1 Endif
&linha += 1 Endif EndDo
if &IsAchouVersao = true &linha += 4 &QtdVazio = 0
&Iscontinua = true do while &Iscontinua = true &ImpCatCodNom = &ExcelDocument.Cells(&linha, 1).Value //PEGA O CODIGO &ObsNom = &ExcelDocument.Cells(&linha, 3).Value //PEGA A OBS
if not &ObsNom.IsEmpty() and not &ImpCatCodNom.IsEmpty()//Se nao For fazio RetiraCaracteresEspeciais.Call(&ObsNom, &ObsNom) //SDT For &sdtItensTabelaImpostoItem in &sdtItensTabelaImposto.Itens If &sdtItensTabelaImpostoItem.ImpCatCodNom = &ImpCatCodNom &sdtObservacaoNota.FromJson(&sdtItensTabelaImpostoItem.ObservacaoLongVarchar) &ObsCod = 0 &IsAchou = false for &sdtObservacaoNotaItem in &sdtObservacaoNota //LOCALIZA OBS if &sdtObservacaoNotaItem.ObsNom = &ObsNom and &sdtObservacaoNotaItem.ObsSts <> 'Z' &IsAchou = true Exit Endif EndFor
if &IsAchou = false //ADICIONA OBS &sdtObservacaoNotaItem = new() &sdtObservacaoNotaItem.ObsNom = &ObsNom &sdtObservacaoNotaItem.ObsSts = 'S' &sdtObservacaoNota.Add(&sdtObservacaoNotaItem) Endif &sdtItensTabelaImpostoItem.ObservacaoLongVarchar = &sdtObservacaoNota.ToJson() EndIf EndFor &QtdVazio = 0 Else &QtdVazio += 1 Endif
&linha += 1 if &QtdVazio > 100 &Iscontinua = false Endif EndDo Endif
//ADICIONA OBSVERVACOES NAO COLOCADAS. For &sdtItensTabelaImpostoItem in &sdtItensTabelaImposto.Itens
&sdtObservacaoNota.FromJson(&sdtItensTabelaImpostoItem.ObservacaoLongVarchar)
For Each Order EmpCod,ImpLctCod,ImpFilCod,ImpUfeCod,ImpGruImpCod,ImpCatCod,ObsCod Where EmpCod = &EmpCod Where ImpLctCod = &sdtItensTabelaImposto.ImpLctCod Where ImpFilCod = &sdtItensTabelaImposto.ImpFilCod Where ImpUfeCod = &sdtItensTabelaImposto.ImpUfeCod Where ImpGruImpCod = &sdtItensTabelaImposto.ImpGruImpCod Where ImpCatCod = &sdtItensTabelaImpostoItem.ImpCatCod
&IsAchou = false for &sdtObservacaoNotaItem in &sdtObservacaoNota //LOCALIZA OBS If ObsNom = &sdtObservacaoNotaItem.ObsNom and &sdtObservacaoNotaItem.ObsSts <> 'Z' &sdtObservacaoNotaItem.ObsSts = 'N' &sdtObservacaoNotaItem.ObsCod = ObsCod &IsAchou = true EndIf EndFor
if &IsAchou = false //ADICIONA OBS &sdtObservacaoNotaItem = new() &sdtObservacaoNotaItem.ObsCod = ObsCod &sdtObservacaoNotaItem.ObsNom = ObsNom &sdtObservacaoNotaItem.ObsSts = 'X' &sdtObservacaoNota.Add(&sdtObservacaoNotaItem) Endif
EndFor
&sdtItensTabelaImpostoItem.ObservacaoLongVarchar = &sdtObservacaoNota.ToJson() EndFor
padraousuarioHora.Call('G', '#IMPORTARTABELAIMPOSTO#', &PesCod, &EmpCod, &sdtItensTabelaImposto.ToJson(), &padDtaMod, &PadDtaHorMod, 'T')
Sub 'validaCFOP' &IsAchouCfop = false For Each Order CfoCod Where CfoCod = &sdtItensTabelaImpostoItem.ImpCfoCod &IsAchouCfop = true Exit EndFor EndSub
